// â”€â”€ Audit Trail Helper â”€â”€
export async function logAudit(
  userId: number,
  restaurantId: number,
  action: string,
  entityType: string,
  entityId: number,
  changes?: any
) {
  try {
    await prisma.auditLog.create({
      data: { userId, restaurantId, action, entityType, entityId, changes },
    });
  } catch {
    /* silent fail â€” audit should never break main flow */
  }
}

