      if (Math.abs(change) >= 5) {
        alerts.push({ type: 'Prix', title: `${newest.ingredient.name}`, detail: `${change > 0 ? '+' : ''}${change.toFixed(1)}%` });
      }
    }

    // Margin alerts
    for (const r of recipes) {
