      const cost = r.ingredients.reduce((s, ri) => s + (ri.quantity / getUnitDivisor(ri.ingredient.unit)) * ri.ingredient.pricePerUnit, 0);
      const margin = ((r.sellingPrice - cost) / r.sellingPrice) * 100;
